import os
import xml.etree.ElementTree as ET
from django.conf import settings
from django.contrib.auth import login
from django.contrib.auth.models import User
from django.http import HttpResponseBadRequest
from django.shortcuts import redirect
from django.views import View
from onelogin.saml2.auth import OneLogin_Saml2_Auth
from onelogin.saml2.utils import OneLogin_Saml2_Utils

class SAMLResponseView(View):
    def post(self, request):
        auth = OneLogin_Saml2_Auth(request)
        auth.process_response()

        if not auth.is_authenticated():
            return HttpResponseBadRequest("Authentication failed.")

        saml_response = request.POST.get('SAMLResponse')
        if not self.validate_xml_structure(saml_response):
            return HttpResponseBadRequest("Invalid SAML Response.")

        user_info = self.extract_user_info(auth)
        user = self.get_or_create_user(user_info)

        login(request, user)
        return redirect(settings.LOGIN_REDIRECT_URL)

    def validate_xml_structure(self, saml_response):
        try:
            root = ET.fromstring(saml_response)
            return root.tag == '{urn:oasis:names:tc:SAML:2.0:assertion}Assertion'
        except ET.ParseError:
            return False

    def extract_user_info(self, auth):
        name_id = auth.get_nameid()
        attributes = auth.get_attributes()
        return {
            'name_id': name_id,
            'email': attributes.get('email', [None])[0],
            'first_name': attributes.get('first_name', [None])[0],
            'last_name': attributes.get('last_name', [None])[0],
        }

    def get_or_create_user(self, user_info):
        user, created = User.objects.get_or_create(
            username=user_info['name_id'],
            defaults={
                'email': user_info['email'],
                'first_name': user_info['first_name'],
                'last_name': user_info['last_name'],
            }
        )
        return user